# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import secrets
import sqlite3
from datetime import datetime, timedelta
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
import os

app = Flask(__name__)

DATABASE = 'users.db'
SMTP_SERVER = os.getenv('SMTP_SERVER', 'smtp.gmail.com')
SMTP_PORT = int(os.getenv('SMTP_PORT', '587'))
SMTP_EMAIL = os.getenv('SMTP_EMAIL', 'your-email@gmail.com')
SMTP_PASSWORD = os.getenv('SMTP_PASSWORD', 'your-password')
RESET_URL_BASE = os.getenv('RESET_URL_BASE', 'http://localhost:5000/reset-password')

def init_db():
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL
        )
    ''')
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS reset_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT NOT NULL,
            token TEXT UNIQUE NOT NULL,
            expires_at TIMESTAMP NOT NULL,
            used INTEGER DEFAULT 0
        )
    ''')
    conn.commit()
    conn.close()

def get_db_connection():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn

def send_reset_email(email, token):
    reset_link = f"{RESET_URL_BASE}?token={token}"
    
    msg = MIMEMultipart('alternative')
    msg['Subject'] = 'Password Reset Request'
    msg['From'] = SMTP_EMAIL
    msg['To'] = email
    
    text = f"Click the link to reset your password: {reset_link}\n\nThis link expires in 1 hour."
    html = f"""
    <html>
      <body>
        <p>Click the link below to reset your password:</p>
        <p><a href="{reset_link}">Reset Password</a></p>
        <p>This link expires in 1 hour.</p>
      </body>
    </html>
    """
    
    part1 = MIMEText(text, 'plain')
    part2 = MIMEText(html, 'html')
    msg.attach(part1)
    msg.attach(part2)
    
    try:
        server = smtplib.SMTP(SMTP_SERVER, SMTP_PORT)
        server.starttls()
        server.login(SMTP_EMAIL, SMTP_PASSWORD)
        server.sendmail(SMTP_EMAIL, email, msg.as_string())
        server.quit()
        return True
    except Exception as e:
        print(f"Email error: {e}")
        return False

@app.route('/api/request-reset', methods=['POST'])
def request_reset():
    data = request.get_json()
    
    if not data or 'email' not in data:
        return jsonify({'error': 'Email is required'}), 400
    
    email = data['email'].strip().lower()
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    conn = get_db_connection()
    cursor = conn.cursor()
    
    user = cursor.execute('SELECT email FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user:
        conn.close()
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.now() + timedelta(hours=1)
    
    cursor.execute(
        'INSERT INTO reset_tokens (email, token, expires_at) VALUES (?, ?, ?)',
        (email, token, expires_at)
    )
    conn.commit()
    conn.close()
    
    email_sent = send_reset_email(email, token)
    
    if not email_sent:
        return jsonify({'error': 'Failed to send email'}), 500
    
    return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

@app.route('/api/reset-password', methods=['POST'])
def reset_password():
    data = request.get_json()
    
    if not data or 'token' not in data or 'new_password' not in data:
        return jsonify({'error': 'Token and new password are required'}), 400
    
    token = data['token']
    new_password = data['new_password']
    
    if len(new_password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    conn = get_db_connection()
    cursor = conn.cursor()
    
    reset_record = cursor.execute(
        'SELECT email, expires_at, used FROM reset_tokens WHERE token = ?',
        (token,)
    ).fetchone()
    
    if not reset_record:
        conn.close()
        return jsonify({'error': 'Invalid token'}), 400
    
    if reset_record['used']:
        conn.close()
        return jsonify({'error': 'Token already used'}), 400
    
    expires_at = datetime.fromisoformat(reset_record['expires_at'])
    if datetime.now() > expires_at:
        conn.close()
        return jsonify({'error': 'Token expired'}), 400
    
    cursor.execute('UPDATE users SET password = ? WHERE email = ?', (new_password, reset_record['email']))
    cursor.execute('UPDATE reset_tokens SET used = 1 WHERE token = ?', (token,))
    
    conn.commit()
    conn.close()
    
    return jsonify({'message': 'Password reset successful'}), 200

if __name__ == '__main__':
    init_db()
    app.run(debug=True)